let report;
try { report = JSON.parse(($input.item.json.stdout || '').trim().split('\n').filter(l=>l.startsWith('{')).pop() || '{}'); }
catch { return []; }
if (!report.broken || report.broken === 0) return [];
const lines = (report.sample || []).map(l => `• ${l.fromSite}${l.fromPath} → ${l.href}`);
return [{ json: {
  priority: 'P1',
  source: 'broken-link-watch',
  message: `${report.broken} broken cross-cluster link${report.broken===1?'':'s'} (of ${report.total}):\n${lines.join('\n')}`,
  url: ($env.EMPIRE_CONSOLE_BASE_URL || 'http://localhost:4327') + '/check/links'
}}];
